def shortestPalindrome(self, s: str) -> str:
    n = len(s)
    for i in range(n):
        for j in range(i+1, n+1):
            palindrome = s[:i] + s[j:] + s[i:j+1]
            if palindrome == palindrome[::-1] and len(palindrome) < len(s):
                s = palindrome
    return s
